    13→/**
    14→ * This provides static methods to convert an XML text into a JSONObject, and to
    15→ * covert a JSONObject into an XML text.
    16→ *
    17→ * @author JSON.org
    18→ * @version 2016-08-10
    19→ */
    20→@SuppressWarnings("boxing")
    21→public class XML {
    22→
    23→    /**
    24→     * Constructs a new XML object.
    25→     */
    26→    public XML() {
    27→    }
    28→
    29→    /** The Character '&amp;'. */
    30→    public static final Character AMP = '&';
    31→
    32→    /** The Character '''. */
    33→    public static final Character APOS = '\'';
    34→
    35→    /** The Character '!'. */
