   231→    /**
   232→     * Scan the content following the named tag, attaching it to the context.
   233→     *
   234→     * @param x
   235→     *            The XMLTokener containing the source string.
   236→     * @param context
   237→     *            The JSONObject that will include the new material.
   238→     * @param name
   239→     *            The tag name.
   240→     * @param config
   241→     *            The XML parser configuration.
   242→     * @param currentNestingDepth
   243→     *            The current nesting depth.
   244→     * @return true if the close tag is processed.
   245→     * @throws JSONException Thrown if any parsing error occurs.
   246→     */
   247→    private static boolean parse(XMLTokener x, JSONObject context, String name, XMLParserConfiguration config, int currentNestingDepth)
   248→            throws JSONException {
   249→        char c;
   250→        int i;
   251→        JSONObject jsonObject = null;
   252→        String string;
   253→        String tagName;
   254→        Object token;
   255→        XMLXsiTypeConverter<?> xmlXsiTypeConverter;
   256→
   257→        // Test for and skip past these forms:
   258→        // <!-- ... -->
   259→        // <! ... >
   260→        // <![ ... ]]>
   261→        // <? ... ?>
   262→        // Report errors for these forms:
   263→        // <>
   264→        // <=
   265→        // <<
   266→
   267→        token = x.nextToken();
   268→
   269→        // <!
   270→
   271→        if (token == BANG) {
   272→            c = x.next();
   273→            if (c == '-') {
   274→                if (x.next() == '-') {
   275→                    x.skipPast("-->");
   276→                    return false;
   277→                }
   278→                x.back();
   279→            } else if (c == '[') {
   280→                token = x.nextToken();
   281→                if ("CDATA".equals(token)) {
   282→                    if (x.next() == '[') {
   283→                        string = x.nextCDATA();
   284→                        if (string.length() > 0) {
   285→                            context.accumulate(config.getcDataTagName(), string);
   286→                        }
   287→                        return false;
   288→                    }
   289→                }
   290→                throw x.syntaxError("Expected 'CDATA['");
   291→            }
   292→            i = 1;
   293→            do {
   294→                token = x.nextMeta();
   295→                if (token == null) {
   296→                    throw x.syntaxError("Missing '>' after '<!'.");
   297→                } else if (token == LT) {
   298→                    i += 1;
   299→                } else if (token == GT) {
   300→                    i -= 1;
   301→                }
   302→            } while (i > 0);
   303→            return false;
   304→        } else if (token == QUEST) {
   305→
   306→            // <?
   307→            x.skipPast("?>");
   308→            return false;
   309→        } else if (token == SLASH) {
   310→
   311→            // Close tag </
   312→
   313→            token = x.nextToken();
   314→            if (name == null) {
   315→                throw x.syntaxError("Mismatched close tag " + token);
   316→            }
   317→            if (!token.equals(name)) {
   318→                throw x.syntaxError("Mismatched " + name + " and " + token);
   319→            }
   320→            if (x.nextToken() != GT) {
   321→                throw x.syntaxError("Misshaped close tag");
   322→            }
   323→            return true;
   324→
   325→        } else if (token instanceof Character) {
   326→            throw x.syntaxError("Misshaped tag");
   327→
   328→            // Open tag <
   329→
   330→        } else {
   331→            tagName = (String) token;
   332→            token = null;
   333→            jsonObject = new JSONObject();
   334→            boolean nilAttributeFound = false;
   335→            xmlXsiTypeConverter = null;
   336→            for (;;) {
   337→                if (token == null) {
   338→                    token = x.nextToken();
   339→                }
   340→                // attribute = value
   341→                if (token instanceof String) {
   342→                    string = (String) token;
   343→                    token = x.nextToken();
   344→                    if (token == EQ) {
   345→                        token = x.nextToken();
   346→                        if (!(token instanceof String)) {
   347→                            throw x.syntaxError("Missing value");
   348→                        }
   349→
   350→                        if (config.isConvertNilAttributeToNull()
   351→                                && NULL_ATTR.equals(string)
   352→                                && Boolean.parseBoolean((String) token)) {
   353→                            nilAttributeFound = true;
   354→                        } else if(config.getXsiTypeMap() != null && !config.getXsiTypeMap().isEmpty()
   355→                                && TYPE_ATTR.equals(string)) {
   356→                            xmlXsiTypeConverter = config.getXsiTypeMap().get(token);
   357→                        } else if (!nilAttributeFound) {
   358→                            Object obj = stringToValue((String) token);
   359→                            if (obj instanceof Boolean) {
   360→                                jsonObject.accumulate(string,
   361→                                        config.isKeepBooleanAsString()
   362→                                                ? ((String) token)
   363→                                                : obj);
   364→                            } else if (obj instanceof Number) {
   365→                                jsonObject.accumulate(string,
   366→                                        config.isKeepNumberAsString()
   367→                                                ? ((String) token)
   368→                                                : obj);
   369→                            } else {
   370→                                jsonObject.accumulate(string, stringToValue((String) token));
   371→                            }
   372→                        }
   373→                        token = null;
   374→                    } else {
   375→                        jsonObject.accumulate(string, "");
   376→                    }
   377→
   378→
   379→                } else if (token == SLASH) {
   380→                    // Empty tag <.../>
   381→                    if (x.nextToken() != GT) {
   382→                        throw x.syntaxError("Misshaped tag");
   383→                    }
   384→                    if (config.getForceList().contains(tagName)) {
   385→                        // Force the value to be an array
   386→                        if (nilAttributeFound) {
   387→                            context.append(tagName, JSONObject.NULL);
   388→                        } else if (jsonObject.length() > 0) {
   389→                            context.append(tagName, jsonObject);
   390→                        } else {
   391→                            context.put(tagName, new JSONArray());
   392→                        }
   393→                    } else {
   394→                        if (nilAttributeFound) {
   395→                            context.accumulate(tagName, JSONObject.NULL);
   396→                        } else if (jsonObject.length() > 0) {
   397→                            context.accumulate(tagName, jsonObject);
   398→                        } else {
   399→                            context.accumulate(tagName, "");
   400→                        }
   401→                    }
   402→                    return false;
   403→
   404→                } else if (token == GT) {
   405→                    // Content, between <...> and </...>
   406→                    for (;;) {
   407→                        token = x.nextContent();
   408→                        if (token == null) {
   409→                            if (tagName != null) {
   410→                                throw x.syntaxError("Unclosed tag " + tagName);
   411→                            }
   412→                            return false;
   413→                        } else if (token instanceof String) {
   414→                            string = (String) token;
   415→                            if (string.length() > 0) {
   416→                                if(xmlXsiTypeConverter != null) {
   417→                                    jsonObject.accumulate(config.getcDataTagName(),
   418→                                            stringToValue(string, xmlXsiTypeConverter));
   419→                                } else {
   420→                                    Object obj = stringToValue((String) token);
   421→                                    if (obj instanceof Boolean) {
   422→                                        jsonObject.accumulate(config.getcDataTagName(),
   423→                                                config.isKeepBooleanAsString()
   424→                                                        ? ((String) token)
   425→                                                        : obj);
   426→                                    } else if (obj instanceof Number) {
   427→                                        jsonObject.accumulate(config.getcDataTagName(),
   428→                                                config.isKeepNumberAsString()
   429→                                                        ? ((String) token)
   430→                                                        : obj);
   431→                                    } else {
   432→                                        jsonObject.accumulate(config.getcDataTagName(), stringToValue((String) token));
   433→                                    }
   434→                                }
   435→                            }
   436→
   437→                        } else if (token == LT) {
   438→                            // Nested element
   439→                            if (currentNestingDepth == config.getMaxNestingDepth()) {
   440→                                throw x.syntaxError("Maximum nesting depth of " + config.getMaxNestingDepth() + " reached");
   441→                            }
   442→
   443→                            if (parse(x, jsonObject, tagName, config, currentNestingDepth + 1)) {
   444→                                if (config.getForceList().contains(tagName)) {
   445→                                    // Force the value to be an array
   446→                                    if (jsonObject.length() == 0) {
   447→                                        context.put(tagName, new JSONArray());
   448→                                    } else if (jsonObject.length() == 1
   449→                                            && jsonObject.opt(config.getcDataTagName()) != null) {
   450→                                        context.append(tagName, jsonObject.opt(config.getcDataTagName()));
   451→                                    } else {
   452→                                        context.append(tagName, jsonObject);
   453→                                    }
   454→                                } else {
   455→                                    if (jsonObject.length() == 0) {
   456→                                        context.accumulate(tagName, "");
   457→                                    } else if (jsonObject.length() == 1
   458→                                            && jsonObject.opt(config.getcDataTagName()) != null) {
   459→                                        context.accumulate(tagName, jsonObject.opt(config.getcDataTagName()));
   460→                                    } else {
   461→                                        if (!config.shouldTrimWhiteSpace()) {
   462→                                            removeEmpty(jsonObject, config);
   463→                                        }
   464→                                        context.accumulate(tagName, jsonObject);
   465→                                    }
   466→                                }
   467→
   468→                                return false;
   469→                            }
   470→                        }
   471→                    }
   472→                } else {
   473→                    throw x.syntaxError("Misshaped tag");
   474→                }
   475→            }
   476→        }
   477→    }
   478→    /**
   479→     * This method removes any JSON entry which has the key set by XMLParserConfiguration.cDataTagName
   480→     * and contains whitespace as this is caused by whitespace between tags. See test XMLTest.testNestedWithWhitespaceTrimmingDisabled.
   481→     * @param jsonObject JSONObject which may require deletion
   482→     * @param config The XMLParserConfiguration which includes the cDataTagName
   483→     */
   484→    private static void removeEmpty(final JSONObject jsonObject, final XMLParserConfiguration config) {
   485→        if (jsonObject.has(config.getcDataTagName()))  {
   486→            final Object s = jsonObject.get(config.getcDataTagName());
   487→            if (s instanceof String) {
   488→                if (isStringAllWhiteSpace(s.toString())) {
   489→                    jsonObject.remove(config.getcDataTagName());
   490→                }
   491→            }
   492→            else if (s instanceof JSONArray) {
   493→                final JSONArray sArray = (JSONArray) s;
   494→                for (int k = sArray.length()-1; k >= 0; k--){
   495→                    final Object eachString = sArray.get(k);
   496→                    if (eachString instanceof String) {
   497→                        String s1 = (String) eachString;
   498→                        if (isStringAllWhiteSpace(s1)) {
   499→                            sArray.remove(k);
   500→                        }
   501→                    }
   502→                }
   503→                if (sArray.isEmpty()) {
   504→                    jsonObject.remove(config.getcDataTagName());
   505→                }
   506→            }
   507→        }
   508→    }
   509→
   510→    private static boolean isStringAllWhiteSpace(final String s) {
   511→        for (int k = 0; k<s.length(); k++){
   512→            final char eachChar = s.charAt(k);
   513→            if (!Character.isWhitespace(eachChar)) {
   514→                return false;
   515→            }
   516→        }
   517→        return true;
   518→    }
