   520→    /**
   521→     * direct copy of {@link JSONObject#stringToNumber(String)} to maintain Android support.
   522→     */
   523→    private static Number stringToNumber(final String val) throws NumberFormatException {
   524→        char initial = val.charAt(0);
   525→        if ((initial >= '0' && initial <= '9') || initial == '-') {
   526→            // decimal representation
   527→            if (isDecimalNotation(val)) {
   528→                // Use a BigDecimal all the time so we keep the original
   529→                // representation. BigDecimal doesn't support -0.0, ensure we
   530→                // keep that by forcing a decimal.
   531→                try {
   532→                    BigDecimal bd = new BigDecimal(val);
   533→                    if(initial == '-' && BigDecimal.ZERO.compareTo(bd)==0) {
   534→                        return Double.valueOf(-0.0);
   535→                    }
   536→                    return bd;
   537→                } catch (NumberFormatException retryAsDouble) {
   538→                    // this is to support "Hex Floats" like this: 0x1.0P-1074
   539→                    try {
   540→                        Double d = Double.valueOf(val);
   541→                        if(d.isNaN() || d.isInfinite()) {
   542→                            throw new NumberFormatException("val ["+val+"] is not a valid number.");
   543→                        }
   544→                        return d;
   545→                    } catch (NumberFormatException ignore) {
   546→                        throw new NumberFormatException("val ["+val+"] is not a valid number.");
   547→                    }
   548→                }
   549→            }
   550→            // block items like 00 01 etc. Java number parsers treat these as Octal.
   551→            if(initial == '0' && val.length() > 1) {
   552→                char at1 = val.charAt(1);
   553→                if(at1 >= '0' && at1 <= '9') {
   554→                    throw new NumberFormatException("val ["+val+"] is not a valid number.");
   555→                }
   556→            } else if (initial == '-' && val.length() > 2) {
   557→                char at1 = val.charAt(1);
   558→                char at2 = val.charAt(2);
   559→                if(at1 == '0' && at2 >= '0' && at2 <= '9') {
   560→                    throw new NumberFormatException("val ["+val+"] is not a valid number.");
   561→                }
   562→            }
   563→            // integer representation.
   564→            // This will narrow any values to the smallest reasonable Object representation
   565→            // (Integer, Long, or BigInteger)
   566→
   567→            // BigInteger down conversion: We use a similar bitLength compare as
   568→            // BigInteger#intValueExact uses. Increases GC, but objects hold
   569→            // only what they need. i.e. Less runtime overhead if the value is
   570→            // long lived.
   571→            BigInteger bi = new BigInteger(val);
   572→            if(bi.bitLength() <= 31){
   573→                return Integer.valueOf(bi.intValue());
   574→            }
   575→            if(bi.bitLength() <= 63){
   576→                return Long.valueOf(bi.longValue());
   577→            }
   578→            return bi;
   579→        }
   580→        throw new NumberFormatException("val ["+val+"] is not a valid number.");
   581→    }
