   583→    /**
   584→     * direct copy of {@link JSONObject#isDecimalNotation(String)} to maintain Android support.
   585→     */
   586→    private static boolean isDecimalNotation(final String val) {
   587→        return val.indexOf('.') > -1 || val.indexOf('e') > -1
   588→                || val.indexOf('E') > -1 || "-0".equals(val);
   589→    }
