   591→    /**
   592→     * This method tries to convert the given string value to the target object
   593→     * @param string String to convert
   594→     * @param typeConverter value converter to convert string to integer, boolean e.t.c
   595→     * @return JSON value of this string or the string
   596→     */
   597→    public static Object stringToValue(String string, XMLXsiTypeConverter<?> typeConverter) {
   598→        if(typeConverter != null) {
   599→            return typeConverter.convert(string);
   600→        }
   601→        return stringToValue(string);
   602→    }
